#!/bin/zsh

# Define the renames for documentation and code
typeset -A renames
renames=(
  "God" "Kernel"
  "GodsPosition" "KernelPosition"
  "God's" "Kernel's"
  "Sin" "StructuralError"
  "Heaven" "ReadinessPeak"
  "Hell" "SaturationBottleneck"
  "Archon" "RegulatoryObstruction"
  "Pleroma" "Manifold"
  "Kenoma" "Vacuum"
  "Beatitudes" "OptimalStates"
  "Mitzvah" "ProtocolConnectivity"
  "Mitzvot" "InvariantProtocols"
  "Valentinian" "Manifold"
  "Theological" "Structural"
  "Gospel" "StateResistance"
  "Psalm" "StateVibration"
  "Conscience" "HeuristicLadder"
  "Dharma" "InvariantField"
  "Dukkha" "EntropyReduction"
  "Submission" "Coupling"
  "Devil" "Deviation"
  "Bible" "CanonicalLedger"
  "Quran" "CanonicalLedger"
  "Torah" "CanonicalLedger"
  "Religious" "Topological"
  "Religion" "TopologicalFramework"
  "AlphaOmegaGodsKingdom" "ManifoldBoundaryCoupling"
  "ApologyPsalm" "ErrorRecoveryInvariant"
  "NoOtherGodBeforeHim" "UniqueKernelInvariance"
  "OnlyGodIsImmune" "KernelImmunityInvariant"
  "HomologyOfReligion" "HomologyOfManifold"
)

# Perform the renames in all markdown and lean files
for old new in ${(kv)renames}; do
    echo "Replacing $old with $new"
    # Case-sensitive replace
    grep -rl "$old" . --include="*.md" --include="*.lean" | xargs sed -i '' "s/$old/$new/g"
    # Capitalized version if not already covered
    OldCap="${(C)old}"
    NewCap="${(C)new}"
    if [[ "$OldCap" != "$old" ]]; then
        echo "Replacing $OldCap with $NewCap"
        grep -rl "$OldCap" . --include="*.md" --include="*.lean" | xargs sed -i '' "s/$OldCap/$NewCap/g"
    fi
done
